.darma-loader-darma-custom-301 {
  width: fit-content;
  font-size: 34px;
  font-family: monospace;
  font-weight: bold;
  text-transform: uppercase;
  color: #0000;
  -webkit-text-stroke: 1px var(--loader-color, #ca8a04);
  background: linear-gradient(90deg,var(--loader-color, #ca8a04),var(--loader-secondary-color, #fde047)) 0/1ch 100% no-repeat text;
  animation: darma-loader-darma-custom-301-l14 1.5s steps(7,jump-none) infinite alternate;
}
.darma-loader-darma-custom-301:before {
  content: "Loading";
}
@keyframes darma-loader-darma-custom-301-l14 {
  to {background-position: 100%}
}

